const a = [
  {"id":8026,"text":"A 60-year-old male presents with end-stage renal disease, hyperkalemia, and metabolic acidosis. He also has hyperparathyroidism as a physiological response to hypocalcemia. What is the patient suffering from?","explanation":null,"reference":null,"responses":[{"text":"Primary hyperparathyroidism","correct":false,"visible":false},{"text":"Tertiary hyperparathyroidism","correct":false,"visible":false},{"text":"Parathyroid hyperplasia","correct":false,"visible":false},{"text":"Secondary hyperparathyroidism","correct":true,"visible":false},{"text":"Parathyroid adenoma","correct":false,"visible":false}]},{"id":8029,"text":"A male was caught red-handed while robbing a chemical store at Jodia bazaar. A mob was gathered and started brutal violence against the robber. One of the men bought a chemical from the nearby store and forced the robber to drink it. The helpless person did as directed, and after a few minutes developed severe convulsions, cyanosis, and dyspnea. Blood-stained froth could be seen in his mouth. What is the most likely cause of poisoning?","explanation":null,"reference":"Biswas G. Review of Forensic Medicine and Toxicology. 3rd ed. Jaypee Brothers Medical Publishers; 2015:  600.","responses":[{"text":"Paraquat","correct":false,"visible":false},{"text":"Corrosive acid","correct":false,"visible":false},{"text":"Organophosphorus","correct":true,"visible":false},{"text":"Dichlorodiphenyltrichloroethane (DDT)","correct":false,"visible":false},{"text":"Bleach","correct":false,"visible":false}]},{"id":8050,"text":"Osteoporosis is a major adverse effect caused by glucocorticoids. Which of the following correctly explains this?","explanation":null,"reference":null,"responses":[{"text":"Decreased collagen synthesis","correct":false,"visible":false},{"text":"Inhibition of calcium absorption","correct":true,"visible":false},{"text":"Increased excretion of calcium","correct":false,"visible":false},{"text":"Stimulation of the hypophyseal-pituitary-adrenal (HPA) axis","correct":false,"visible":false},{"text":"Decreased production of prostaglandins","correct":false,"visible":false}]},{"id":8076,"text":"Which of the following insulin analogs is a long-acting preparation?","explanation":null,"reference":null,"responses":[{"text":"Insulin aspart","correct":false,"visible":false},{"text":"Insulin lispro","correct":false,"visible":false},{"text":"Insulin glulisine","correct":false,"visible":false},{"text":"Neutral protamine Hagedorn (NPH)","correct":false,"visible":false},{"text":"Insulin glargine","correct":true,"visible":false}]},{"id":8212,"text":"Thyroid hormone preparations like levothyroxine act on which of the following receptors?","explanation":null,"reference":null,"responses":[{"text":"Intracellular receptors","correct":true,"visible":false},{"text":"G-protein linked receptors","correct":false,"visible":false},{"text":"Tyrosine kinase receptors","correct":false,"visible":false},{"text":"Cytokine receptors","correct":false,"visible":false},{"text":"Ion channel-linked receptors","correct":false,"visible":false}]},{"id":8237,"text":"A farmer’s wife while picking cotton from cotton pods develops nausea and dyspnea. When taken to hospital she was diagnosed with organophosphorus poisoning. What is the most likely route of entry of poison in this patient?","explanation":null,"reference":null,"responses":[{"text":"Contact with mucous membrane","correct":false,"visible":false},{"text":"Inhalation","correct":false,"visible":false},{"text":"Gastrointestinal","correct":false,"visible":false},{"text":"Eyes","correct":false,"visible":false},{"text":"Contact with intact skin","correct":true,"visible":false}]},{"id":8240,"text":"The anti-inflammatory effects of glucocorticoids are due to which fundamental mechanism?","explanation":null,"reference":null,"responses":[{"text":"Inhibit macrophage phagocytosis","correct":false,"visible":false},{"text":"Decrease T-cell function","correct":false,"visible":false},{"text":"Inhibit leukotriene and prostaglandin synthesis via inhibition of phospholipase A2","correct":true,"visible":false},{"text":"Simulate histamine release from mast cells","correct":false,"visible":false},{"text":"Increase capillary permeability","correct":false,"visible":false}]},{"id":8248,"text":"A drug addict keeps scratching his body and complains that he feels insects creeping on his body. What is he suffering from?","explanation":null,"reference":"Le T, Bhushan V, Qiu C, et al., eds. First Aid for the USMLE Step 1 2023. 33rd ed. McGraw Hill; 2023: 578.","responses":[{"text":"Visual hallucinations","correct":false,"visible":false},{"text":"Auditory hallucinations","correct":false,"visible":false},{"text":"Illusions","correct":false,"visible":false},{"text":"Paranoid delusion","correct":false,"visible":false},{"text":"Tactile hallucinations","correct":true,"visible":false}]},{"id":8266,"text":"A man, charged with murder, pleaded insanity in a court of law. He was brought before the medical officer for examination. How will the medical officer differentiate between true and feigned insanity?","explanation":null,"reference":"Biswas, Gautam. Review of Forensic Medicine and Toxicology. 3rd ed., Jaypee Brothers Medical Publishers, 2015: 408.","responses":[{"text":"In feigned insanity peculiar facial expressions are absent","correct":true,"visible":false},{"text":"In feigned insanity the onset is gradual","correct":false,"visible":false},{"text":"In feigned insanity fatigue does not set in","correct":false,"visible":false},{"text":"In feigned insanity the person appreciates repeated examination","correct":false,"visible":false},{"text":"In feigned insanity behavioral disturbances are uniform","correct":false,"visible":false}]},{"id":8484,"text":"An asthmatic individual who is on regular therapy for the past year develops symptoms of Cushing's syndrome. What is the most likely etiology?","explanation":null,"reference":"Sattar HA. Fundamentals of Pathology: Medical Course and Step 1 Review. Pathoma.com; 2021: 171.","responses":[{"text":"Iatrogenic","correct":true,"visible":false},{"text":"Pituitary tumor","correct":false,"visible":false},{"text":"Idiopathic","correct":false,"visible":false},{"text":"Ectopic ACTH secreting tumor","correct":false,"visible":false},{"text":"Adrenal tumor","correct":false,"visible":false}]},{"id":8490,"text":"A 6-year-old child presents with signs and symptoms of adrenal insufficiency. He also has a long history of mucocutaneous candidiasis. What is the most likely diagnosis?","explanation":null,"reference":"Husebye, Eystein S., et al. “Autoimmune Polyendocrine Syndromes.” The New England Journal of Medicine, 22 Mar. 2018, https://www.ncbi.nlm.nih.gov/pmc/articles/PMC6007870/.","responses":[{"text":"Congenital adrenal hyperplasia","correct":false,"visible":false},{"text":"Mccune-Albright syndrome","correct":false,"visible":false},{"text":"Autoimmune polyendocrinopathy","correct":true,"visible":false},{"text":"Post-tuberculosis adrenalitis","correct":false,"visible":false},{"text":"MEN-1 syndrome","correct":false,"visible":false}]},{"id":8611,"text":"The poisoning caused by which of the following substances presents with gastrointestinal irritation, black-colored urine, and loin pain?","explanation":null,"reference":"Biswas G. Review of Forensic Medicine and Toxicology. 3rd ed. Jaypee Brothers Medical Publishers; 2015:  603.","responses":[{"text":"Arsenic","correct":false,"visible":false},{"text":"Organophosphorus","correct":false,"visible":false},{"text":"Opium","correct":false,"visible":false},{"text":"Strychnine","correct":false,"visible":false},{"text":"Naphthalene","correct":true,"visible":false}]},{"id":8630,"text":"Excessive growth hormone release in adults leads to which condition?","explanation":null,"reference":"Kumar V, Abbas AK, Aster JC, Cotran RS, Robbins SL. Robbins \u0026 Cotran Pathologic Basis of Disease. 10th ed. Elsevier; 2020: 1072.","responses":[{"text":"Goiter","correct":false,"visible":false},{"text":"Acromegaly","correct":true,"visible":false},{"text":"Achondroplasia","correct":false,"visible":false},{"text":"Gigantism","correct":false,"visible":false},{"text":"Dwarfism","correct":false,"visible":false}]},{"id":8663,"text":"Hürthle cell variant is seen in which of the following?","explanation":null,"reference":"Kumar V, Abbas AK, Aster JC, Cotran RS, Robbins SL. Robbins \u0026 Cotran Pathologic Basis of Disease. 10th ed. Elsevier; 2020: 1089.","responses":[{"text":"Papillary carcinoma","correct":false,"visible":false},{"text":"Medullary cell carcinoma","correct":false,"visible":false},{"text":"Marginal zone lymphoma","correct":false,"visible":false},{"text":"Anaplastic carcinoma","correct":false,"visible":false},{"text":"Follicular carcinoma","correct":true,"visible":false}]},{"id":8673,"text":"What is the most common source of ectopic adrenocorticotropic hormone (ACTH) production?","explanation":null,"reference":"(1) Ectopic corticotropin production - An Overview | ScienceDirect topics. Accessed December 14, 2022. https://www.sciencedirect.com/topics/medicine-and-dentistry/ectopic-corticotropin-production\r\n\r\n(2) Kumar V, Abbas AK, Aster JC, Cotran RS, Robbins SL. Robbins \u0026 Cotran Pathologic Basis of Disease. 10th ed. Elsevier; 2020: 1123.","responses":[{"text":"Large cell carcinoma","correct":false,"visible":false},{"text":"Bronchial carcinoid","correct":false,"visible":false},{"text":"Adenocarcinoma","correct":false,"visible":false},{"text":"Small cell lung carcinoma","correct":true,"visible":false},{"text":"Squamous cell carcinoma","correct":false,"visible":false}]},{"id":10235,"text":"Which of the following statements is incorrect for the pancreas?","explanation":null,"reference":null,"responses":[{"text":"Pancreas is a lobulated organ","correct":false,"visible":false},{"text":"Tail is related to the hilum of spleen","correct":false,"visible":false},{"text":"Head lies in the concavity of duodenum","correct":false,"visible":false},{"text":"Uncinate is present behind the superior mesenteric vessel","correct":false,"visible":false},{"text":"Islets are mostly present in its head region","correct":true,"visible":false}]},{"id":10236,"text":"Which of the following statements is incorrect about the pituitary gland?","explanation":null,"reference":null,"responses":[{"text":"Pars nervosa consists of unmyelinated axons","correct":false,"visible":false},{"text":"Adenohypophysis develops from Rathke's pouch","correct":false,"visible":false},{"text":"Lies in sella turcica","correct":false,"visible":false},{"text":"Also called epiphyseal cerebri","correct":true,"visible":false},{"text":"Blood supply by the branches of internal carotid artery","correct":false,"visible":false}]},{"id":10294,"text":"A 30-year-old woman complains of increased weight gain, fatiguability, depression, and poor memory for the past 3 months. She has pale dry skin and raised blood pressure. What is the most common investigation that will be advised?","explanation":null,"reference":null,"responses":[{"text":"Complete blood count","correct":false,"visible":false},{"text":"TSH levels","correct":true,"visible":false},{"text":"Liver function tests","correct":false,"visible":false},{"text":"ECG","correct":false,"visible":false},{"text":"Fasting lipid profile","correct":false,"visible":false}]},{"id":10296,"text":"In untreated primary hypothyroidism which of the following thyroid function test results are most likely to be seen?","explanation":null,"reference":null,"responses":[{"text":"Increased free T4, increased TSH, increased T3","correct":false,"visible":false},{"text":"Decreased free T4, increased TSH, decreased T3","correct":true,"visible":false},{"text":"Decreased free T4, decreased or normal TSH, decreased T3","correct":false,"visible":false},{"text":"Increased free T4, decreased TSH, increased T3","correct":false,"visible":false},{"text":"Increased free T4, decreased TSH, decreased T3","correct":false,"visible":false}]},{"id":10299,"text":"When considering thyroid hormone replacement therapy in case of primary hypothyroidism which of the following precautions must be taken?","explanation":null,"reference":null,"responses":[{"text":"Thyroid hormone pill should be taken with breakfast","correct":false,"visible":false},{"text":"Thyroxine should be taken on an empty stomach in the morning","correct":true,"visible":false},{"text":"Elderly people should be started at higher doses of thyroxine","correct":false,"visible":false},{"text":"Thyroxine should be stopped as soon as the patient becomes euthyroid","correct":false,"visible":false},{"text":"Thyroid hormone needs to be replaced for three months","correct":false,"visible":false}]},{"id":10300,"text":"A patient has thyroid and liver disease with altered thyroid-binding globulin (TBG) levels. Which of the following has the highest affinity for TBG?","explanation":null,"reference":null,"responses":[{"text":"Albumin","correct":false,"visible":false},{"text":"T3","correct":false,"visible":false},{"text":"RT3","correct":false,"visible":false},{"text":"T4","correct":true,"visible":false},{"text":"Triiodothyronine","correct":false,"visible":false}]},{"id":10301,"text":"Which of the following is an incorrect statement about the thyroid gland?","explanation":null,"reference":null,"responses":[{"text":"Superior thyroid artery is a branch of external carotid artery","correct":false,"visible":false},{"text":"Calcitonin is formed by follicular cells","correct":true,"visible":false},{"text":"Inferior thyroid vein drains into left brachiocephalic vein","correct":false,"visible":false},{"text":"It lies in front of 2nd and 3rd tracheal rings","correct":false,"visible":false},{"text":"Its capsule is formed by pretracheal fascia","correct":false,"visible":false}]},{"id":10308,"text":"A 54-year-old female presents to the outpatient clinic with a complaint of attacks of numbness on and off in her lower limbs. Her bone profile shows serum calcium 1.93 mmo/L (2.10-2.65 mmol/L), serum urea 4.2 mmol/L (3.6-6.6 mmol/L), serum phosphorus 2.56 mmol/L (1.75-1.9 mmol/L) and blood parathyroid hormone 12 pmol/L (15-62 pmol/L). What is she suffering from?","explanation":null,"reference":null,"responses":[{"text":"Vitamin D deficiency","correct":false,"visible":false},{"text":"Hypoparathyroidism","correct":true,"visible":false},{"text":"Pseudohypoparathyroidism","correct":false,"visible":false},{"text":"Chronic kidney disease","correct":false,"visible":false},{"text":"Renal osteodystrophy","correct":false,"visible":false}]},{"id":10311,"text":"24-year-old primigravida presents to the clinic with anemia and lethargy. Her mother had a thyroid disorder. She is advised thyroid profile. Which of the following levels will be checked?","explanation":null,"reference":null,"responses":[{"text":"TSH and total T4","correct":false,"visible":false},{"text":"Anti-thyroid antibodies","correct":false,"visible":false},{"text":"Serum TSH, free T3, free T4","correct":true,"visible":false},{"text":"Serum TSH","correct":false,"visible":false},{"text":"Serum TSH and free rT3","correct":false,"visible":false}]},{"id":10322,"text":"A 54-year-old, married woman para-2 comes to the clinic with the complaint of weight gain and lethargy for the past 3 months. She had her last menstrual period 6 years back. Her blood pressure is 150/90 mmHg, her pulse is 65/min, and is regular bilaterally. Her body mass index (BMI) falls in the obese range. Her eyes are puffy, she complains of breathlessness, and cold intolerance, her skin is coarse and her abdomen has white striations present. What is the best diagnostic test for this woman?","explanation":"The best diagnostic test for this 54-year-old woman is **serum TSH level**. Her clinical presentation is highly suggestive of hypothyroidism. The symptoms of weight gain, lethargy, cold intolerance, puffy eyes, and coarse skin are typical features of hypothyroidism. Additionally, her blood pressure is elevated, which can be seen in hypothyroidism.\r\n\r\nIn this case, measuring the serum TSH level is crucial because an elevated TSH level along with low levels of thyroid hormones (T3 and T4) would confirm the diagnosis of primary hypothyroidism. Primary hypothyroidism is the most common cause of hypothyroidism and is characterized by inadequate thyroid hormone production due to dysfunction of the thyroid gland itself.","reference":"Kumar V, Abbas AK, Aster JC. Robbins and Cotran Pathologic Basis of Disease. 9th ed. Elsevier Saunders; 2015: 1086.","responses":[{"text":"Serum cortisol","correct":false,"visible":false},{"text":"Oral glucose tolerance test and TSH","correct":false,"visible":false},{"text":"Oral glucose tolerance test","correct":false,"visible":false},{"text":"Serum cortisol and TSH","correct":false,"visible":false},{"text":"Serum TSH level","correct":true,"visible":false}]},{"id":10323,"text":"A 5-year-old girl presents to a rural dispensary and her height and weight are \u003c2nd percentile and 3rd percentile respectively. There is no significant family history. Clinical examination is otherwise unremarkable. Which of the following conditions is most likely the cause of short stature in this girl?","explanation":null,"reference":null,"responses":[{"text":"Familial short stature","correct":false,"visible":false},{"text":"Turner syndrome","correct":false,"visible":false},{"text":"Malnutrition","correct":true,"visible":false},{"text":"Hypothyroidism","correct":false,"visible":false},{"text":"Growth hormone deficiency","correct":false,"visible":false}]},{"id":10332,"text":"A 46-year-old male presents to the outpatient department with complaints of increased appetite, nausea, headache, fatigue muscle weakness, and pain in the limbs. His laboratory results show serum calcium 2.92 mmol/L (2.10-2.65 mmmol/L), serum urea 5.9 mmol/L (3.6-6.6 mmol/L), and blood parathyroid hormone 97 pmol/L (15-62 pmol/L). What is the most probable diagnosis?","explanation":null,"reference":null,"responses":[{"text":"Acute renal failure","correct":false,"visible":false},{"text":"Osteoporosis","correct":false,"visible":false},{"text":"Vitamin D deficiency","correct":false,"visible":false},{"text":"Thyroid surgery","correct":false,"visible":false},{"text":"Parathyroid adenoma","correct":true,"visible":false}]},{"id":10334,"text":"A 39-year-old female visits the endocrinologist with her routine lipid profile result. The doctor suspects the metabolic syndrome in the patient. Which of the following lipid profile results meets the criteria for this syndrome?","explanation":null,"reference":null,"responses":[{"text":"HDL \u003c70 mg/L","correct":false,"visible":false},{"text":"LDL \u003e80 mg/L","correct":false,"visible":false},{"text":"Triglycerides \u003e150 mg/L","correct":true,"visible":false},{"text":"Cholesterol \u003e200 mg/L","correct":false,"visible":false},{"text":"VLDL \u003e30 mg/L","correct":false,"visible":false}]},{"id":10335,"text":"A 54-year-old female visits an endocrinologist with the complaint of not being able to notice the slipped-off slipper from the foot during walking until she looks at her feet. History suggests that she is a known case of diabetes for the past 10 years. What is the most likely diagnosis?","explanation":null,"reference":null,"responses":[{"text":"Neuropathy","correct":true,"visible":false},{"text":"Charcot foot","correct":false,"visible":false},{"text":"Diabetic foot","correct":false,"visible":false},{"text":"Angiopathy","correct":false,"visible":false},{"text":"Peripheral vascular disease","correct":false,"visible":false}]},{"id":10336,"text":"Which of the following catalyzes the conversion of glucose into sorbitol?","explanation":null,"reference":null,"responses":[{"text":"Aminotransferase","correct":false,"visible":false},{"text":"Aldose reductase","correct":true,"visible":false},{"text":"Pyruvate dehydrogenase","correct":false,"visible":false},{"text":"NADH dehydrogenase","correct":false,"visible":false},{"text":"Lactate dehydrogenase","correct":false,"visible":false}]},{"id":10338,"text":"40-year-old presents to the outpatient department with a complaint of neck swelling for the past month. Her biopsy results show rapidly dividing follicular cells with optically clear nuclei, intracellular inclusions, and concentric calcifications. The patient is suffering from which of the following?","explanation":null,"reference":null,"responses":[{"text":"Medullary carcinoma","correct":false,"visible":false},{"text":"Papillary carcinoma","correct":true,"visible":false},{"text":"Follicular carcinoma","correct":false,"visible":false},{"text":"Follicular adenoma","correct":false,"visible":false},{"text":"Benign nodular hyperplasia","correct":false,"visible":false}]},{"id":10339,"text":"Which of the following is characteristic of Hashimoto thyroiditis?","explanation":null,"reference":null,"responses":[{"text":"Follicular cell hyperplasia and scalloping of colloid","correct":false,"visible":false},{"text":"Diffuse fibrous deposition between atrophic follicles","correct":false,"visible":false},{"text":"Multiple hyperplastic nodules and compressed thyroid at periphery","correct":false,"visible":false},{"text":"Granulomatous inflammation against colloid","correct":false,"visible":false},{"text":"Lymphoid follicles with germinal centers and Hurtlhe cells","correct":true,"visible":false}]},{"id":10340,"text":"A 30-year-old male presents to the clinic with neck swelling and a history of weight loss of 5 kg over a month. On examination, exophthalmos, diffuse thyroid swelling, and non-pitting edema over the legs. His laboratory results show elevated T4 and decreased TSH. What will be seen in his thyroid biopsy?","explanation":null,"reference":null,"responses":[{"text":"Multiple hyperplastic nodules and compressed thyroid at periphery","correct":false,"visible":false},{"text":"Diffuse fibrous deposition between atrophic follicles","correct":false,"visible":false},{"text":"Granulomatous inflammation against colloid","correct":false,"visible":false},{"text":"Lymphoid follicles with germinal centers and Hurtle cells","correct":false,"visible":false},{"text":"Follicular cell hyperplasia and scalloping of colloid","correct":true,"visible":false}]},{"id":10341,"text":"Which of the following is incorrectly matched with their classification?","explanation":null,"reference":null,"responses":[{"text":"Metformin -\u003e biguanide","correct":false,"visible":false},{"text":"Nateglinide -\u003e phenylalanine derivative","correct":false,"visible":false},{"text":"Repaglinide -\u003e Thiazolidinedione","correct":true,"visible":false},{"text":"Glyburide -\u003e sulfonylurea","correct":false,"visible":false},{"text":"Acarbose -\u003e alpha glucosidase inhibitor","correct":false,"visible":false}]},{"id":10342,"text":"Which of the following drugs regulates the transcription of insulin-responsive genes including the genes responsible for lipid and glucose metabolism and insulin signal transduction?","explanation":null,"reference":null,"responses":[{"text":"Metformin","correct":false,"visible":false},{"text":"Repaglinide","correct":false,"visible":false},{"text":"Glipizide","correct":false,"visible":false},{"text":"Pioglitazone","correct":true,"visible":false},{"text":"Acarbose","correct":false,"visible":false}]},{"id":10347,"text":"Which of the following drugs is incorrectly matched with its adverse effects?","explanation":null,"reference":null,"responses":[{"text":"Pioglitazone -\u003e weight loss","correct":true,"visible":false},{"text":"Acarbose -\u003e bloating, flatulence","correct":false,"visible":false},{"text":"Glyburide -\u003e disulfiram-like effect","correct":false,"visible":false},{"text":"Repaglinide -\u003e Hypoglycemia","correct":false,"visible":false},{"text":"Metformin -\u003e lactic acidosis","correct":false,"visible":false}]},{"id":10348,"text":"Which of the following is incorrectly matched?","explanation":null,"reference":null,"responses":[{"text":"Betamethasone: long acting glucocorticoid","correct":false,"visible":false},{"text":"Hydrocortisone: short to medium acting glucocorticoid","correct":false,"visible":false},{"text":"Triamcinolone: intermediate acting glucocorticoid","correct":false,"visible":false},{"text":"Fludrocortisone: mineralocorticoid","correct":false,"visible":false},{"text":"Dexamethasone: short acting glucocorticoid","correct":true,"visible":false}]},{"id":10350,"text":"A man is brought to the district hospital after being bitten by a snake on foot. He complained of localized pain and swelling of the foot. He then started bleeding through his mouth and nose. On examination, petechial hemorrhage could be seen under his skin. He got bitten by which type of snake?","explanation":null,"reference":"Biswas G. Review of Forensic Medicine and Toxicology. 3rd ed. Jaypee Brothers Medical Publishers; 2015: 529.","responses":[{"text":"Cobra","correct":false,"visible":false},{"text":"Kraits","correct":false,"visible":false},{"text":"Viper","correct":true,"visible":false},{"text":"Elapids","correct":false,"visible":false},{"text":"Sea snake","correct":false,"visible":false}]},{"id":10351,"text":"A young boy is brought to the hospital in a state of shock and fright after being bitten by a cobra on hand. What is the next step of management after reassuring the patient?","explanation":null,"reference":"Biswas G. Review of Forensic Medicine and Toxicology. 3rd ed. Jaypee Brothers Medical Publishers; 2015: 529.","responses":[{"text":"Wash the wound with soap and water","correct":false,"visible":false},{"text":"Immobilize the bitten limb","correct":true,"visible":false},{"text":"Tie ligature around the wound","correct":false,"visible":false},{"text":"Cut the wound open","correct":false,"visible":false},{"text":"Suck the wound","correct":false,"visible":false}]},{"id":10353,"text":"What is an interpretation of external stimuli or objects known as?","explanation":null,"reference":null,"responses":[{"text":"Imaginary","correct":false,"visible":false},{"text":"None of these","correct":false,"visible":false},{"text":"Perception","correct":true,"visible":false},{"text":"Hallucination","correct":false,"visible":false},{"text":"Illusion","correct":false,"visible":false}]},{"id":10355,"text":"Which of the following is used for the screening of congenital hypothyroidism?","explanation":null,"reference":null,"responses":[{"text":"TSH level","correct":true,"visible":false},{"text":"Total T4 and T3 level","correct":false,"visible":false},{"text":"Thyroid level","correct":false,"visible":false},{"text":"Free T4 and T3 level","correct":false,"visible":false},{"text":"Thyrotropin level","correct":false,"visible":false}]},{"id":10371,"text":"A patient is suspected to have Addison's disease due to the impairment of the hypothalamic-pituitary-adrenal axis (HPA) axis. Which of the following drugs can be given to the patient to confirm this diagnosis?","explanation":null,"reference":null,"responses":[{"text":"Cortisol","correct":false,"visible":false},{"text":"Alendronate","correct":false,"visible":false},{"text":"Insulin","correct":false,"visible":false},{"text":"Metyrapone","correct":true,"visible":false},{"text":"Propylthiouracil","correct":false,"visible":false}]},{"id":10372,"text":"A 25-year-old lactating female comes to the office with a painful swelling on her left breast for the last 5 days and fever for the last 2 days. The swelling has enlarged progressively with increasing pain. On examination, the swelling is located in the left upper quadrant, is erythematous, soft, and tender. What is the most likely diagnosis?","explanation":null,"reference":"Kumar V, Abbas AK, Aster JC. Robbins and Cotran Pathologic Basis of Disease. 9th ed. Elsevier Saunders; 2015: 1046.","responses":[{"text":"Cyst","correct":false,"visible":false},{"text":"Fibroadenoma","correct":false,"visible":false},{"text":"Abscess","correct":true,"visible":false},{"text":"Phyllodes tumor","correct":false,"visible":false},{"text":"Carcinoma","correct":false,"visible":false}]},{"id":10375,"text":"A 34-year-old woman presents with a painless swelling on the left side of her neck for the past 3 months. According to her, it has increased only slightly in size. Her pulse is 90 beats/min, BP is 110/70 mmHg, the temperature is 99 degrees Fahrenheit. On examination, the swelling moves on deglutition. What is the most appropriate initial investigation in this patient?","explanation":null,"reference":null,"responses":[{"text":"Thyroid scan","correct":false,"visible":false},{"text":"CT scan neck","correct":false,"visible":false},{"text":"X-ray neck","correct":false,"visible":false},{"text":"Ultrasound neck","correct":true,"visible":false},{"text":"MRI scan neck","correct":false,"visible":false}]},{"id":10385,"text":"An infant presents to the outpatient department with complaints of lethargy, difficulty in feeding, and constipation for the past 1 month. On examination, the baby has a protruded tongue, husky cry, and an umbilical hernia. Laboratory results show an increased level of TSH and reduced levels of free T4. What is the most likely diagnosis?","explanation":null,"reference":"Khan PA. Basis of Pediatrics. 10th ed. Paramount Books (Pvt.) Ltd; 2018: 455.","responses":[{"text":"Secondary hypothyroidism","correct":false,"visible":false},{"text":"Sepsis","correct":false,"visible":false},{"text":"Hyperparathyroidism","correct":false,"visible":false},{"text":"Primary hypothyroidism","correct":true,"visible":false},{"text":"Mucopolysaccharidosis","correct":false,"visible":false}]},{"id":10386,"text":"An 11-year-old girl has a short stature and increased weight. She also complains of cold intolerance and increased sleep. Her bone age is delayed. Lab results show an increased level of TSH and a reduced free T4. What is the most likely diagnosis?","explanation":null,"reference":"Khan PA. Basis of Pediatrics. 10th ed. Paramount Books (Pvt.) Ltd; 2018: 454.","responses":[{"text":"Congenital hyperthyroidism","correct":false,"visible":false},{"text":"Acquired hypothyroidism","correct":true,"visible":false},{"text":"Turner syndrome","correct":false,"visible":false},{"text":"Congenital hypothyroidism","correct":false,"visible":false},{"text":"Hyperparathyroidism","correct":false,"visible":false}]},{"id":11131,"text":"Which of the following hormones does not use cyclic adenosine monophosphate (cAMP) as a second messenger?","explanation":"**Estrogen** is the hormone that does not use **cyclic adenosine monophosphate (cAMP)** as a second messenger.\r\n\r\nHormones that use cAMP as a second messenger belong to the class of **peptide hormones or protein hormones**. When these hormones bind to their specific receptors on the cell surface, it activates the receptor, leading to the generation of cAMP inside the cell. cAMP then acts as a second messenger, activating protein kinases and initiating various intracellular signaling cascades.\r\n\r\nHowever, **estrogen** is a **steroid hormone**, and it uses a different mechanism for signal transduction. Steroid hormones like estrogen are lipophilic and can cross the cell membrane to bind to intracellular receptors located in the cytoplasm or nucleus. This hormone-receptor complex then directly interacts with specific DNA sequences, regulating gene expression and protein synthesis within the target cells.","reference":"Hall JE, Hall ME. Guyton and Hall Textbook of Medical Physiology. 14th ed. Elsevier; 2020: 924.","responses":[{"text":"Luteinizing hormone (LH)","correct":false,"visible":false},{"text":"Calcitonin","correct":false,"visible":false},{"text":"Estrogen","correct":true,"visible":false},{"text":"Follicle-stimulating hormone (FSH)","correct":false,"visible":false},{"text":"Glucagon","correct":false,"visible":false}]},{"id":12788,"text":"What percentage of patients with Addison's disease have vitiligo?","explanation":null,"reference":"Ralston SH, Penman ID, Strachan MWJ, Hobson RP, eds. Davidson’s Principles and Practice of Medicine. 23rd ed. Elsevier; 2018: 672.","responses":[{"text":"1-2%","correct":false,"visible":false},{"text":"90%","correct":false,"visible":false},{"text":"10-20%","correct":true,"visible":false},{"text":"5%","correct":false,"visible":false},{"text":"60-70%","correct":false,"visible":false}]},{"id":12789,"text":"Which part of the anterior pituitary secretes most of the hormones?","explanation":null,"reference":"Mescher AL. Junqueira’s Basic Histology: Text and Atlas. 14th ed. McGraw-Hill Medical; 2015: 417-419.","responses":[{"text":"Pars distalis","correct":true,"visible":false},{"text":"Pars nervosa","correct":false,"visible":false},{"text":"Pars tuberalis","correct":false,"visible":false},{"text":"Pars intermedia","correct":false,"visible":false},{"text":"Hypothalamus","correct":false,"visible":false}]},{"id":12792,"text":"Which of the following is a life-threatening complication that may occur with improper management of diabetic ketoacidosis?","explanation":"While patients with DKA often present with an elevated serum potassium, they are typically potassium depleted. The acidosis present in DKA promotes the shift of potassium from the intracellular to the extracellular space. Improper management of DKA, especially aggressive insulin therapy without adequate potassium replacement, can cause a rapid shift of potassium into cells, leading to life-threatening hypokalemia. On the other hand, if a patient with DKA is not given insulin and fluids appropriately, the hyperkalemia can persist or worsen, leading to cardiac arrhythmias.","reference":"Ralston SH, Penman ID, Strachan MWJ, Hobson RP, eds. Davidson’s Principles and Practice of Medicine. 23rd ed. Elsevier; 2018: 738.","responses":[{"text":"Renal failure","correct":false,"visible":false},{"text":"Cerebral edema","correct":false,"visible":false},{"text":"Hyperglycemia","correct":false,"visible":false},{"text":"Dehydration","correct":false,"visible":false},{"text":"Hyperkalemia","correct":true,"visible":false}]},{"id":12793,"text":"A 28-year-old woman presents to the endocrine clinic with secondary amenorrhea and galactorrhoea for the last 6 months. Her general physical and systemic examination is normal. Lab investigations reveal, prolactin = 3250 mU/L (60–620), free T4 = 15.5 pmol/L (11.5–22.7), thyroid-stimulating hormone (TSH) = 2.5 mU/L (0.35–5.5), and urine pregnancy test is negative. What is the most likely diagnosis?","explanation":null,"reference":"Ralston SH, Penman ID, Strachan MWJ, Hobson RP, eds. Davidson’s Principles and Practice of Medicine. 23rd ed. Elsevier; 2018: 683.","responses":[{"text":"Primary hypothyroidism","correct":false,"visible":false},{"text":"Grave disease","correct":false,"visible":false},{"text":"Cushing's syndrome","correct":false,"visible":false},{"text":"Hypopituitarism","correct":false,"visible":false},{"text":"Prolactinoma","correct":true,"visible":false}]},{"id":13259,"text":"Which of the following increases the hypoglycemic effects of sulfonylurea?","explanation":null,"reference":"Karen Whalen, Radhakrishnan R, Field C. Lippincott Illustrated Reviews: Pharmacology. 7th ed. Lippincott Williams \u0026 Wilkins; 2019: 318.","responses":[{"text":"Oral contraceptive","correct":false,"visible":false},{"text":"Chloramphenicol","correct":true,"visible":false},{"text":"Phenytoin","correct":false,"visible":false},{"text":"Phenobarbital","correct":false,"visible":false},{"text":"Rifampicin","correct":false,"visible":false}]},{"id":13260,"text":"Which of the following attenuates the hypoglycemic effects of sulfonylurea?","explanation":null,"reference":"Karen Whalen, Radhakrishnan R, Field C. Lippincott Illustrated Reviews: Pharmacology. 7th ed. Lippincott Williams \u0026 Wilkins; 2019: 318.","responses":[{"text":"Hydrochlorothiazide","correct":true,"visible":false},{"text":"Penicillin","correct":false,"visible":false},{"text":"Chloramphenicol","correct":false,"visible":false},{"text":"Aspirin","correct":false,"visible":false},{"text":"Propanolol","correct":false,"visible":false}]},{"id":13264,"text":"How do 2nd generation sulfonylureas differ from the 1st generation ones?","explanation":null,"reference":"Katzung BG, ed. Basic \u0026 Clinical Pharmacology. 14th ed. McGraw Hill; 2018: 758.","responses":[{"text":"They do not lower blood sugar in nondiabetic subjects","correct":false,"visible":false},{"text":"They are less prone to cause hypoglycemia","correct":false,"visible":false},{"text":"They are more potent","correct":true,"visible":false},{"text":"They are effective in emergency situations","correct":false,"visible":false},{"text":"They are longer-acting","correct":false,"visible":false}]},{"id":13265,"text":"Sulfonylureas are a drug of choice for which of the following?","explanation":null,"reference":"Karen Whalen, Radhakrishnan R, Field C. Lippincott Illustrated Reviews: Pharmacology. 7th ed. Lippincott Williams \u0026 Wilkins; 2019: 317.","responses":[{"text":"Type 1 diabetes melltus","correct":false,"visible":false},{"text":"Steroid-induced diabetes","correct":false,"visible":false},{"text":"Type 2 diabetes melltus","correct":true,"visible":false},{"text":"All of these","correct":false,"visible":false},{"text":"Gestational diabetes","correct":false,"visible":false}]},{"id":13266,"text":"Which of these drugs inhibits the synthesis of thyroid hormone and inhibits the peripheral conversion of T4 to T3 hormone?","explanation":null,"reference":"Karen Whalen, Radhakrishnan R, Field C. Lippincott Illustrated Reviews: Pharmacology. 7th ed. Lippincott Williams \u0026 Wilkins; 2019: 308.","responses":[{"text":"Methimazole","correct":false,"visible":false},{"text":"Propylthiouracil","correct":true,"visible":false},{"text":"Carbimazole","correct":false,"visible":false},{"text":"Perchlorate","correct":false,"visible":false},{"text":"Thiocyanate","correct":false,"visible":false}]},{"id":13269,"text":"A 35-year-old, mother of two children, comes to the clinic with a history of amenorrhea for 6 months and headaches for 3 months, For some days she is also experiencing increased milk production from her breasts. She has concerns about her vision as she recently escaped an accident while overtaking a school bus while changing lanes. On examination she is not pregnant, her blood pressure is normal and she is afebrile. On optometric examination her lateral vision was found to be reduced. Which of the following lab test findings is most likely to be present in this woman?","explanation":null,"reference":"Kumar V, Abbas AK, Aster JC. Robbins and Cotran Pathologic Basis of Disease. 9th ed. Elsevier Saunders; 2015: 1079.","responses":[{"text":"Decreased serum sodium","correct":false,"visible":false},{"text":"Increased serum cortisol","correct":false,"visible":false},{"text":"Hyperprolactinemia","correct":true,"visible":false},{"text":"Decreased Serum TSH","correct":false,"visible":false},{"text":"Lack of growth hormone secretion","correct":false,"visible":false}]},{"id":13272,"text":"Anaplastic tumors of the thyroid gland have which of the following characteristic?","explanation":null,"reference":"Sattar HA. Fundamentals of Pathology: Medical Course and Step 1 Review. Pathoma.com; 2021: 164.","responses":[{"text":"Partially differentiation","correct":false,"visible":false},{"text":"Undifferentiated","correct":true,"visible":false},{"text":"Benign","correct":false,"visible":false},{"text":"Variant of medullary carcinomas","correct":false,"visible":false},{"text":"Well-differentiated","correct":false,"visible":false}]},{"id":13273,"text":"A patient diagnosed with Graves disease is taking propylthiouracil and propranolol. What is the adverse effect of the anti-thyroid medication?","explanation":null,"reference":"Katzung BG, ed. Basic \u0026 Clinical Pharmacology. 14th ed. McGraw Hill; 2018: 695.","responses":[{"text":"Tremors","correct":false,"visible":false},{"text":"Pancreatitis","correct":false,"visible":false},{"text":"Arrhythmias","correct":false,"visible":false},{"text":"Agranulocytosis","correct":true,"visible":false},{"text":"Dry mouth","correct":false,"visible":false}]},{"id":13274,"text":"Which drug increases insulin sensitivity by increasing peripheral receptors for insulin?","explanation":null,"reference":"Karen Whalen, Radhakrishnan R, Field C. Lippincott Illustrated Reviews: Pharmacology. 7th ed. Lippincott Williams \u0026 Wilkins; 2019: 319.","responses":[{"text":"Pioglitazone","correct":true,"visible":false},{"text":"Metformin","correct":false,"visible":false},{"text":"Pramlinitide","correct":false,"visible":false},{"text":"Acarbose","correct":false,"visible":false},{"text":"Glipizide","correct":false,"visible":false}]},{"id":13276,"text":"In an elderly man with hypothyroidism, rapid administration of levothyroxine can cause which of the following?","explanation":null,"reference":"(1) Le T, Bhushan V. First Aid for the USMLE Step 1 2022. 32nd ed. McGraw-Hill Education; 2022: 362.\r\n\r\n(2) Ralston SH, Penman ID, Strachan MWJ, Hobson RP, eds. Davidson’s Principles and Practice of Medicine. 23rd ed. Elsevier; 2018: 641.","responses":[{"text":"Seizures","correct":false,"visible":false},{"text":"All of these","correct":false,"visible":false},{"text":"Pancreatitis","correct":false,"visible":false},{"text":"Respiratory depression","correct":false,"visible":false},{"text":"Overstimulation of heart","correct":true,"visible":false}]},{"id":13277,"text":"Which of the following features is unique to Grave disease?","explanation":null,"reference":"Ralston SH, Penman ID, Strachan MWJ, Hobson RP, eds. Davidson’s Principles and Practice of Medicine. 23rd ed. Elsevier; 2018: 636.","responses":[{"text":"Exophthalmos","correct":true,"visible":false},{"text":"Palpitations","correct":false,"visible":false},{"text":"Lid retration","correct":false,"visible":false},{"text":"Lid lag","correct":false,"visible":false},{"text":"Weight loss","correct":false,"visible":false}]},{"id":13278,"text":"A 29-year-old patient comes with complaints of fever and sore throat. On examination, her throat is congested and her thyroid is palpable. Labs reveal that TSH is 6.8 mmol/dL and T4 and T3 are normal but at the lower end of the reference range. What is the possible diagnosis?","explanation":null,"reference":"Ralston SH, Penman ID, Strachan MWJ, Hobson RP, eds. Davidson’s Principles and Practice of Medicine. 23rd ed. Elsevier; 2018: 642.","responses":[{"text":"Solitary thyroid nodule","correct":false,"visible":false},{"text":"Hashimoto thyroiditis","correct":false,"visible":false},{"text":"Sick euthyroid syndrome","correct":false,"visible":false},{"text":"Subclinical hypothyroidism","correct":true,"visible":false},{"text":"Endemic goiter","correct":false,"visible":false}]},{"id":13279,"text":"What is the most common side effect of insulin?","explanation":null,"reference":"Karen Whalen, Radhakrishnan R, Field C. Lippincott Illustrated Reviews: Pharmacology. 7th ed. Lippincott Williams \u0026 Wilkins; 2019: 313.","responses":[{"text":"Pancreatitis","correct":false,"visible":false},{"text":"Nause and vomitting","correct":false,"visible":false},{"text":"Lipodystrophy","correct":false,"visible":false},{"text":"Hyperglycemia","correct":false,"visible":false},{"text":"Hypoglycemia","correct":true,"visible":false}]},{"id":13280,"text":"Which of the following is a consequence of long-term glucocorticoid therapy?","explanation":null,"reference":"Le T, Bhushan V. First Aid for the USMLE Step 1 2022. 32nd ed. McGraw-Hill Education; 2022: 119.","responses":[{"text":"Hypoglycemia","correct":false,"visible":false},{"text":"Osteoporosis","correct":true,"visible":false},{"text":"Precocious puberty","correct":false,"visible":false},{"text":"Alopecia","correct":false,"visible":false},{"text":"Hepatotoxicity","correct":false,"visible":false}]},{"id":13282,"text":"Pituitary tumors are a feature of which of the following?","explanation":null,"reference":"Le T, Bhushan V. First Aid for the USMLE Step 1 2022. 32nd ed. McGraw-Hill Education; 2022: 358.","responses":[{"text":"MEN2A","correct":false,"visible":false},{"text":"MEN1","correct":true,"visible":false},{"text":"Zollinger-Ellison syndrome","correct":false,"visible":false},{"text":"SBLA syndrome","correct":false,"visible":false},{"text":"MEN2B","correct":false,"visible":false}]},{"id":13283,"text":"A 19-year-old girl is brought to the emergency room by her family who reports that she swallowed a liquid poison in a suicide attempt. On examination, she is bradycardic, hypotensive, flaccid, has excessive salivation, and has convulsions and fasciculations. What is the likely cause of poisoning?","explanation":null,"reference":"Biswas G. Review of Forensic Medicine and Toxicology. 3rd ed. Jaypee Brothers Medical Publishers; 2015:  538.","responses":[{"text":"Organophosphorus","correct":true,"visible":false},{"text":"Benzodiazepines","correct":false,"visible":false},{"text":"Cocaine","correct":false,"visible":false},{"text":"Barbiturates","correct":false,"visible":false},{"text":"Atropine","correct":false,"visible":false}]},{"id":13551,"text":"An 8-year-old child presents to the clinic with short stature. A growth hormone deficiency is suspected. Which of the following lab values is the most appropriate test to perform in this child?","explanation":null,"reference":"(1) Ralston SH, Penman ID, Strachan MWJ, Hobson RP, eds. Davidson’s Principles and Practice of Medicine. 23rd ed. Elsevier; 2018: 682.\r\n\r\n(2) Gillis D, Magiel E, Terespolsky N, Naugolny L, Strich D. Clonidine stimulation test for GH deficiency: a new look at sample timing. Endocrine Practice: Official Journal of the American College of Endocrinology and the American Association of Clinical Endocrinologists. Accessed December 13, 2022. https://pubmed.ncbi.nlm.nih.gov/88610/","responses":[{"text":"Clonidine stimulation test","correct":true,"visible":false},{"text":"Insulin induced hypoglycemia","correct":false,"visible":false},{"text":"Sleep-induced GH levels","correct":false,"visible":false},{"text":"Random GH levels","correct":false,"visible":false},{"text":"Exercise-induced GH levels","correct":false,"visible":false}]},{"id":13553,"text":"A woman taking corticosteroids for chronic interstitial lung disease (ILD) develops moon facies and weakness. Her lung functions have improved over time. What is the most appropriate management?","explanation":null,"reference":"Ralston SH, Penman ID, Strachan MWJ, Hobson RP, eds. Davidson’s Principles and Practice of Medicine. 23rd ed. Elsevier; 2018: 671.","responses":[{"text":"Adrenalectomy","correct":false,"visible":false},{"text":"Give ketoconazole","correct":false,"visible":false},{"text":"Gradually taper off steroids","correct":true,"visible":false},{"text":"Immediately stop steroids","correct":false,"visible":false},{"text":"Confirm diagnosis of Cushing syndrome","correct":false,"visible":false}]},{"id":13558,"text":"Which of the following is a feature of papillary carcinoma?","explanation":null,"reference":"Sattar HA. Fundamentals of Pathology: Medical Course and Step 1 Review. Pathoma.com; 2021: 164.","responses":[{"text":"Auer rods","correct":false,"visible":false},{"text":"Psammoma bodies","correct":true,"visible":false},{"text":"Roth spots","correct":false,"visible":false},{"text":"Reed Sternberg cells","correct":false,"visible":false},{"text":"Anitschkow cells","correct":false,"visible":false}]},{"id":13559,"text":"Which of the following is an effect of regular insulin?","explanation":null,"reference":"Le T, Bhushan V. First Aid for the USMLE Step 1 2022. 32nd ed. McGraw-Hill Education; 2022: 360.","responses":[{"text":"Increased lipolysis","correct":false,"visible":false},{"text":"Conversion of glycogen to glucose","correct":false,"visible":false},{"text":"Breakdown of triglycerides","correct":false,"visible":false},{"text":"Protein degradation","correct":false,"visible":false},{"text":"Increased K+ uptake by cells","correct":true,"visible":false}]},{"id":13560,"text":"A 31-year-old female develops shortness of breath. On examination, she is observed to have a raised jugular venous pulse (JVP) and muffled heart sounds. She has a history of hypothyroidism. Which of the following is the likely reason for the new findings?","explanation":null,"reference":"(1) Chahine J, Ala CK, Gentry JL, Pantalone KM, Klein AL. Pericardial diseases in patients with hypothyroidism. Heart (British Cardiac Society). Accessed December 14, 2022. https://pubmed.ncbi.nlm.nih.gov/30948517/\r\n\r\n\r\n(2) Ralston SH, Penman ID, Strachan MWJ, Hobson RP, eds. Davidson’s Principles and Practice of Medicine. 23rd ed. Elsevier; 2018: 543.","responses":[{"text":"Cor pulmonale","correct":false,"visible":false},{"text":"None of these","correct":false,"visible":false},{"text":"Pericardial effusion","correct":true,"visible":false},{"text":"Asthma","correct":false,"visible":false},{"text":"Myocardial infarction","correct":false,"visible":false}]},{"id":13561,"text":"A young female presents to the clinic with tremors, excessive sweating, and tachycardia. On examination, a solitary thyroid nodule with irregular margins is observed. What would be the next appropriate investigation?","explanation":null,"reference":"Penman ID, Ralston S, Strachan MWJ, Hobson RP. Davidson’s Principles and Practice of Medicine. 24th ed. Elsevier; 2022: 636.","responses":[{"text":"Excisional biopsy","correct":false,"visible":false},{"text":"Isotope scan","correct":true,"visible":false},{"text":"Incisional biopsy","correct":false,"visible":false},{"text":"Fine need aspiration cytology","correct":false,"visible":false},{"text":"Trucut biopsy","correct":false,"visible":false}]},{"id":13562,"text":"Which of the following is characteristic of papillary thyroid carcinoma?","explanation":null,"reference":"Sattar HA. Fundamentals of Pathology: Medical Course and Step 1 Review. Pathoma.com; 2021: 164.","responses":[{"text":"Auer rods","correct":false,"visible":false},{"text":"Clear 'Orphan-Annie' nuclei","correct":true,"visible":false},{"text":"Reed Sternberg cells","correct":false,"visible":false},{"text":"Roth spots","correct":false,"visible":false},{"text":"Polygonal spindle cells","correct":false,"visible":false}]},{"id":13567,"text":"A patient reports to the psychiatry ward with a firm belief that somebody wants to kill him. What is this type of delusion called?","explanation":null,"reference":"Semple D, Smyth R. Oxford Handbook of Psychiatry. 3rd ed. Oxford University Press; 2013: 101.","responses":[{"text":"Delusion of grandeur","correct":false,"visible":false},{"text":"Delusion of influence","correct":false,"visible":false},{"text":"Paranoid delusion","correct":true,"visible":false},{"text":"Delusion of self-reproach","correct":false,"visible":false},{"text":"Nihilistic delusion","correct":false,"visible":false}]},{"id":13568,"text":"A young male patient is suffering from a delusional belief where he imagines that he is going to be poisoned by his relatives, wife, and son and they will rob his property. What is this type of delusion called?","explanation":null,"reference":"Semple D, Smyth R. Oxford Handbook of Psychiatry. 3rd ed. Oxford University Press; 2013: 101.","responses":[{"text":"Delusion of persecution","correct":true,"visible":false},{"text":"Delusion of influence","correct":false,"visible":false},{"text":"Delusion of self-reproach","correct":false,"visible":false},{"text":"Delusion of grandeur","correct":false,"visible":false},{"text":"Delusion of reference","correct":false,"visible":false}]},{"id":13569,"text":"High calcitonin levels with a nest of polygonal cells and amyloid deposits on cytology is seen in which of the following?","explanation":null,"reference":"Sattar HA. Fundamentals of Pathology: Medical Course and Step 1 Review. Pathoma.com; 2021: 164.","responses":[{"text":"Papillary thyroid carcinoma","correct":false,"visible":false},{"text":"Follicular thyroid carcinoma","correct":false,"visible":false},{"text":"Thyroid adenoma","correct":false,"visible":false},{"text":"Medullary thyroid carcinoma","correct":true,"visible":false},{"text":"Anaplastic thyroid carcinoma","correct":false,"visible":false}]},{"id":13570,"text":"Which of the following changes is made to the dosage of levothyroxine for a pregnant woman in her 2nd trimester?","explanation":null,"reference":"Ralston SH, Penman ID, Strachan MWJ, Hobson RP, eds. Davidson’s Principles and Practice of Medicine. 23rd ed. Elsevier; 2018: 641.","responses":[{"text":"Switch to triiodothyronine","correct":false,"visible":false},{"text":"Give both levothyroxine and triiodothyronine","correct":false,"visible":false},{"text":"Stop medication","correct":false,"visible":false},{"text":"Increase dosage","correct":true,"visible":false},{"text":"Decrease dosage","correct":false,"visible":false}]},{"id":13571,"text":"Which virus can cause diabetes mellitus?","explanation":null,"reference":"Yoo SG, Han KD, Lee KH, La Y, Kwon DE, Han SH. Impact of cytomegalovirus disease on new-onset type 2 diabetes mellitus: population-based matched case-control cohort study. Diabetes \u0026 Metabolism Journal. Accessed December 14, 2022. https://pubmed.ncbi.nlm.nih.gov/30688050/","responses":[{"text":"Hepatitis B","correct":false,"visible":false},{"text":"Hepatitis A","correct":false,"visible":false},{"text":"CMV","correct":true,"visible":false},{"text":"EBV","correct":false,"visible":false},{"text":"Hepatitis C","correct":false,"visible":false}]},{"id":13572,"text":"Which of the following has an autoimmune etiology?","explanation":null,"reference":"Sattar HA. Fundamentals of Pathology: Medical Course and Step 1 Review. Pathoma.com; 2021: 161.","responses":[{"text":"Pseudohypoparathyroidism","correct":false,"visible":false},{"text":"Addison disease","correct":false,"visible":false},{"text":"De Quervain thyroiditis","correct":false,"visible":false},{"text":"Cushing syndrome","correct":false,"visible":false},{"text":"Grave's disease","correct":true,"visible":false}]},{"id":13574,"text":"A 20-year-old male presents with fever, fatigue, and an enlarged thyroid gland that is tender to palpation. He recovers completely in about a week. What is the most likely diagnosis?","explanation":null,"reference":"Sattar HA. Fundamentals of Pathology: Medical Course and Step 1 Review. Pathoma.com; 2021: 163.","responses":[{"text":"Postpartum thyroiditis","correct":false,"visible":false},{"text":"De Quervain thyroiditis","correct":true,"visible":false},{"text":"Grave disease","correct":false,"visible":false},{"text":"Reidel thyroiditis","correct":false,"visible":false},{"text":"Hashimoto thyroiditis","correct":false,"visible":false}]},{"id":13575,"text":"A 7-year-old boy, who is healthy and school-going, comes to the outpatient department accompanied by his parents, for the evaluation of short stature. He is usually lethargic and is not performing well in school. What is the most likely diagnosis?","explanation":null,"reference":"Ralston SH, Penman ID, Strachan MWJ, Hobson RP, eds. Davidson’s Principles and Practice of Medicine. 23rd ed. Elsevier; 2018: 717.","responses":[{"text":"Cretinism","correct":true,"visible":false},{"text":"None of these","correct":false,"visible":false},{"text":"Pubertal goitre","correct":false,"visible":false},{"text":"Endemic goitre","correct":false,"visible":false},{"text":"Hashimoto thyroiditis","correct":false,"visible":false}]},{"id":13576,"text":"Which drug causes a decrease in insulin resistance by upregulating peroxisome proliferator-activated receptor gamma (PPAR-γ)?","explanation":null,"reference":"Karen Whalen, Radhakrishnan R, Field C. Lippincott Illustrated Reviews: Pharmacology. 7th ed. Lippincott Williams \u0026 Wilkins; 2019: 317.","responses":[{"text":"Tolbutamide","correct":false,"visible":false},{"text":"Metformin","correct":false,"visible":false},{"text":"Pioglitazone","correct":true,"visible":false},{"text":"Human insulin","correct":false,"visible":false},{"text":"Acarbose","correct":false,"visible":false}]}
]

export default a